import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useParams, Navigate } from 'react-router-dom';

// Import các trang của bạn
import Home from './pages/Home/Home';
import SearchPage from './pages/Search/Search';
import Ranking from './pages/Ranking/Ranking';
import Profile from './pages/Profile/Profile';
import FocusMode from './pages/Focus/FocusMode';
import Login from './pages/Auth/Login';
import Register from './pages/Auth/Register';
import AdminUpload from './pages/Admin/AdminUpload';

const ProfileWrapper = () => {
  const { userId } = useParams();
  return <Profile key={userId} />;
};

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));

  const handleLogout = () => {
    localStorage.clear();
    setUser(null);
    window.location.href = '/login';
  };

  return (
    <Router>
      <nav style={{ padding: '15px 40px', background: '#1db954', display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: 'white' }}>
        <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
          <Link to="/" style={{ fontWeight: 'bold', textDecoration: 'none', color: 'white', fontSize: '20px' }}>P2TUNES 🎵</Link>
          <Link to="/search" style={{ textDecoration: 'none', color: 'white' }}>Tìm kiếm</Link>
          <Link to="/ranking" style={{ textDecoration: 'none', color: 'white' }}>BXH</Link>
        </div>

        <div>
          {user ? (
            <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
              <Link to={`/profile/${user._id || user.id}`} style={{ color: 'white', textDecoration: 'none' }}>
                Chào, <b>{user.username}</b>
              </Link>
              <button onClick={handleLogout} style={{ background: 'red', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '5px', cursor: 'pointer' }}>Thoát</button>
            </div>
          ) : (
            <div style={{ display: 'flex', gap: '15px' }}>
              <Link to="/login" style={{ color: 'white', textDecoration: 'none' }}>Đăng nhập</Link>
              <Link to="/register" style={{ color: 'white', textDecoration: 'none', border: '1px solid white', padding: '2px 10px', borderRadius: '5px' }}>Đăng ký</Link>
            </div>
          )}
        </div>
      </nav>

      <div style={{ minHeight: '80vh', padding: '20px' }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/search" element={<SearchPage />} />
          <Route path="/ranking" element={<Ranking />} />
          <Route path="/focus" element={<FocusMode />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/upload" element={<AdminUpload />} />
          <Route path="/profile/:userId" element={<ProfileWrapper />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </div>

      <footer style={{ textAlign: 'center', padding: '20px', color: '#888' }}>
        © 2025 P2TUNES
      </footer>
    </Router>
  );
}

export default App;
